```class Solution {
public:
    int maximumLengthSubstring(string s) {
        int n = s.size();
        int res = 0;
        unordered_map<char, int> count;
        int l = 0;
        for (int r = 0; r < n; r++) {
            count[s[r]]++;
            while (count.size() > 2 || (count.size() == 2 && count.begin()->second > 2)) {
                count[s[l]]--;
                if (count[s[l]] == 0) count.erase(s[l]);
                l++;
            }
            res = max(res, r - l + 1);
        }
        return res;
    }
};
